const rows = $input.all().map(i => i.json);

if (rows.length === 0 || (rows.length === 1 && rows[0].id_imagem === 'sem_arquivo')) {
  return [{ json: { success: true, files: [], total: 0 } }];
}

const byEndereco = {};
const allFiles = [];

for (const row of rows) {
  if (!row.id_imagem) continue;

  const id = row.id_imagem;
  const detalhe = row.detalhe || 'comprovante';
  const endereco = row.endereco || '';
  const idPasta = row.id_pasta || '';

  const isVideo = detalhe.includes('video') || detalhe.includes('gravacao');
  const isPdf   = detalhe.includes('relatorio') || detalhe.includes('pdf') || detalhe.includes('apresentacao') || detalhe.includes('zip');
  const isImage = !isVideo && !isPdf;

  const file = {
    id_imagem: id,
    id_pasta: idPasta,
    detalhe,
    endereco,
    isImage,
    isVideo,
    isPdf,
    thumbnailUrl: isImage ? `https://drive.google.com/thumbnail?id=${id}&sz=w800` : null,
    previewUrl: `https://drive.google.com/file/d/${id}/preview`,
    viewUrl: `https://drive.google.com/file/d/${id}/view`,
    downloadUrl: `https://drive.google.com/uc?id=${id}&export=download`
  };

  allFiles.push(file);

  const key = endereco || '_sem_endereco';
  if (!byEndereco[key]) byEndereco[key] = [];
  byEndereco[key].push(file);
}

return [{ json: {
  success: true,
  files: allFiles,
  files_by_endereco: byEndereco,
  total: allFiles.length
}}];

// SHA-256 puro JS - zero dependencias, funciona em qualquer versao do n8n
// Se voce tem amor a sua vida, nao mexa nisso!
function sha256(message) {
  function rightRotate(value, amount) {
    return (value >>> amount) | (value << (32 - amount));
  }
  const mathPow = Math.pow;
  const maxWord = mathPow(2, 32);
  let lengthProperty = 'length';
  let i, j;
  let result = '';
  const words = [];
  const asciiBitLength = message[lengthProperty] * 8;
  let hash = [];
  const k = [];
  let primeCounter = k[lengthProperty];
  const isComposite = {};
  for (let candidate = 2; primeCounter < 64; candidate++) {
    if (!isComposite[candidate]) {
      for (i = 0; i < 313; i += candidate) isComposite[i] = candidate;
      hash[primeCounter] = (mathPow(candidate, 0.5) * maxWord) | 0;
      k[primeCounter++] = (mathPow(candidate, 1/3) * maxWord) | 0;
    }
  }
  message += '\x80';
  while (message[lengthProperty] % 64 - 56) message += '\x00';
  for (i = 0; i < message[lengthProperty]; i++) {
    j = message.charCodeAt(i);
    if (j >> 8) return '';
    words[i >> 2] |= j << ((3 - i) % 4) * 8;
  }
  words[words[lengthProperty]] = ((asciiBitLength / maxWord) | 0);
  words[words[lengthProperty]] = asciiBitLength;
  for (j = 0; j < words[lengthProperty];) {
    const w = words.slice(j, j += 16);
    const oldHash = hash.slice(0);
    for (i = 0; i < 64; i++) {
      const w15 = w[i - 15], w2 = w[i - 2];
      const a = hash[0], e = hash[4];
      const temp1 = hash[7]
        + (rightRotate(e, 6) ^ rightRotate(e, 11) ^ rightRotate(e, 25))
        + ((e & hash[5]) ^ (~e & hash[6]))
        + k[i]
        + (w[i] = i < 16 ? w[i] : (
          w[i - 16]
          + (rightRotate(w15, 7) ^ rightRotate(w15, 18) ^ (w15 >>> 3))
          + w[i - 7]
          + (rightRotate(w2, 17) ^ rightRotate(w2, 19) ^ (w2 >>> 10))
        ) | 0);
      const temp2 = (rightRotate(a, 2) ^ rightRotate(a, 13) ^ rightRotate(a, 22))
        + ((a & hash[1]) ^ (a & hash[2]) ^ (hash[1] & hash[2]));
      hash = [(temp1 + temp2) | 0].concat(hash);
      hash[4] = (hash[4] + temp1) | 0;
      hash.length = 8;
    }
    hash = hash.map((h, i) => (h + oldHash[i]) | 0);
  }
  for (i = 0; i < 8; i++) {
    for (j = 3; j + 1; j--) {
      const b = (hash[i] >> (j * 8)) & 255;
      result += ((b < 16) ? 0 : '') + b.toString(16);
    }
  }
  return result;
}

function simpleHash(password, salt) {
  let h = sha256(salt + password);
  for (let i = 0; i < 1000; i++) h = sha256(h + salt + i);
  return h;
}

function randomHex(len) {
  let result = '';
  const chars = '0123456789abcdef';
  for (let i = 0; i < len; i++) result += chars[Math.floor(Math.random() * 16)];
  return result;
}

function generateUUID() {
  const h = randomHex(32);
  return `${h.slice(0,8)}-${h.slice(8,12)}-4${h.slice(13,16)}-${(parseInt(h[16],16)&3|8).toString(16)}${h.slice(17,20)}-${h.slice(20,32)}`;
}

