function base64url(str) {
  if (typeof btoa !== 'undefined') {
    return btoa(str).replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');
  }
  return Buffer.from(str,'binary').toString('base64')
    .replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');
}

function hmacSHA256(key, data) {
  const blockSize = 64;
  let keyBytes = [];
  for (let i = 0; i < key.length; i++) keyBytes.push(key.charCodeAt(i));
  if (keyBytes.length > blockSize) {
    const hk = sha256(key);
    keyBytes = [];
    for (let i = 0; i < hk.length; i += 2) keyBytes.push(parseInt(hk.substr(i,2), 16));
  }
  while (keyBytes.length < blockSize) keyBytes.push(0);
  const oKey = keyBytes.map(b => String.fromCharCode(b ^ 0x5c)).join('');
  const iKey = keyBytes.map(b => String.fromCharCode(b ^ 0x36)).join('');
  return sha256(oKey + sha256(iKey + data));
}

const users = $input.all().map(i => i.json);
const inputPassword = $items('Processar Login')[0].json.passwordInput;

if (users.length === 0) throw new Error('INVALID_CREDENTIALS');
const user = users[0];
if (!user.password_hash?.includes(':')) throw new Error('INVALID_CREDENTIALS');

const [salt, storedHash] = user.password_hash.split(':');
const inputHash = simpleHash(inputPassword, salt);
if (inputHash !== storedHash) throw new Error('INVALID_CREDENTIALS');

const JWT_SECRET = 'CHANGE_THIS_SECRET_IN_PRODUCTION';
const header  = base64url(JSON.stringify({ alg: 'HS256', typ: 'JWT' }));
const payload = base64url(JSON.stringify({
  sub: user.id, email: user.email, role: user.role, name: user.name,
  iat: Math.floor(Date.now()/1000),
  exp: Math.floor(Date.now()/1000) + 28800
}));
const sig = hmacSHA256(JWT_SECRET, header + '.' + payload);
const sigBytes = [];
for (let i = 0; i < sig.length; i += 2) sigBytes.push(parseInt(sig.substr(i,2), 16));
const sigB64 = base64url(String.fromCharCode(...sigBytes));
const token = `${header}.${payload}.${sigB64}`;

return [{ json: {
  success: true, token,
  user: { id: user.id, name: user.name, email: user.email, avatar: user.avatar||null, role: user.role }
}}];

