const { action } = $input.first().json;
const headers = $input.first().json.headers || {};
if (['login','health_check','register_user'].includes(action)) return $input.all();

const authHeader = headers['authorization'] || headers['Authorization'] || '';
const token = authHeader.startsWith('Bearer ') ? authHeader.slice(7).trim() : '';
if (!token) throw new Error('TOKEN_MISSING');

const parts = token.split('.');
if (parts.length !== 3) throw new Error('INVALID_TOKEN');
const [hdr, pay, sig] = parts;

const JWT_SECRET = 'CHANGE_THIS_SECRET_IN_PRODUCTION';
const expectedHex = hmacSHA256(JWT_SECRET, `${hdr}.${pay}`);
const expBytes = [];
for (let i = 0; i < expectedHex.length; i+=2) expBytes.push(parseInt(expectedHex.substr(i,2),16));

function base64url(str){
  if(typeof btoa!=='undefined')return btoa(str).replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');
  return Buffer.from(str,'binary').toString('base64').replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');
}
const expectedSig = base64url(String.fromCharCode(...expBytes));
if (sig !== expectedSig) throw new Error('INVALID_TOKEN');

let data;
try {
  const padded = pay.replace(/-/g,'+').replace(/_/g,'/');
  if(typeof atob!=='undefined') data = JSON.parse(atob(padded));
  else data = JSON.parse(Buffer.from(padded,'base64').toString('utf8'));
} catch { throw new Error('INVALID_TOKEN'); }

if (data.exp && Math.floor(Date.now()/1000) > data.exp) throw new Error('TOKEN_EXPIRED');

const items = $input.all();
items[0].json.authenticatedUser = data;
return items;

// ============================================================
// SANITIZADOR DE INPUT — Prevencao de SQL Injection
// Escapa aspas simples em TODOS os campos do body
// Roda ANTES de qualquer query BigQuery
// ============================================================
function sanitize(val) {
  if (val === null || val === undefined) return '';
  if (typeof val !== 'string') return String(val);
  return val
    .replace(/'/g, "\\'")
    .replace(/\\/g, '\\\\')
    .replace(/[\x00-\x1f]/g, '');
}

function sanitizeObj(obj) {
  if (!obj || typeof obj !== 'object') return obj;
  const clean = {};
  for (const [k, v] of Object.entries(obj)) {
    if (typeof v === 'object' && v !== null) {
      clean[k] = sanitizeObj(v);
    } else {
      clean[k] = sanitize(v);
    }
  }
  return clean;
}

const items = $input.all();
const item = items[0].json;
item.body = sanitizeObj(item.body || {});
item.query = sanitizeObj(item.query || {});
